#include <iostream>
#include <random>

namespace Random {
    inline std::mt19937 mt{ 42 };

    inline int get(int min, int max) {
        std::uniform_int_distribution<int> dist{ min, max };
        return dist(mt);
    }
}

int main() {
    int n{};
    std::cin >> n;

    int count1{ 0 }, count2{ 0 }, count3{ 0 };
    int count4{ 0 }, count5{ 0 }, count6{ 0 };
    bool allValid{ true };

    for (int i{ 0 }; i < n; ++i) {
        int roll{ Random::get(1, 6) };
        if (roll == 1) ++count1;
        else if (roll == 2) ++count2;
        else if (roll == 3) ++count3;
        else if (roll == 4) ++count4;
        else if (roll == 5) ++count5;
        else if (roll == 6) ++count6;
        else allValid = false;
    }

    int uniqueFaces{ 0 };
    if (count1 > 0) ++uniqueFaces;
    if (count2 > 0) ++uniqueFaces;
    if (count3 > 0) ++uniqueFaces;
    if (count4 > 0) ++uniqueFaces;
    if (count5 > 0) ++uniqueFaces;
    if (count6 > 0) ++uniqueFaces;

    std::cout << "Total rolls: " << n << '\n';
    if (allValid)
        std::cout << "All valid: yes\n";
    else
        std::cout << "All valid: no\n";
    std::cout << "Unique faces seen: " << uniqueFaces << '\n';

    return 0;
}

