#include <iostream>
#include <random>

namespace Random {
    inline std::mt19937 mt{ 123 };

    inline int get(int min, int max) {
        std::uniform_int_distribution<int> dist{ min, max };
        return dist(mt);
    }
}

int main() {
    int lo{}, hi{};

    while (std::cin >> lo >> hi) {
        int value{ Random::get(lo, hi) };
        std::cout << "Range [" << lo << ", " << hi << "]: " << value;
        if (value >= lo && value <= hi)
            std::cout << " (valid)\n";
        else
            std::cout << " (INVALID)\n";
    }

    return 0;
}
